const message = new AIMessage({
  content: "",
  tool_calls: [
    {
      name: "multiply",
      args: { a: 42, b: 7 },
      id: "tool_call_id",
      type: "tool_call",
    },
  ],
});

const result = await toolNode.invoke({ messages: [message] });

// Output:
// { messages: [
//   ToolMessage {
//     content: "Error: The ultimate error\n Please fix your mistakes.",
//     name: "multiply",
//     tool_call_id: "tool_call_id",
//     status: "error"
//   }
// ]}
